#include <stdio.h>
#include <stdint.h>

// Structure to represent an RGB pixel
typedef struct {
  uint8_t R;
  uint8_t G;
  uint8_t B;
} Pixel;

// Function to convert an RGB image to grayscale
void grayscaleConversion(Pixel *pixels, int width, int height) {
  for (int i = 0; i < width * height; i++) {
    uint8_t grayscaleValue = 0.299 * pixels[i].R + 0.587 * pixels[i].G + 0.114 * pixels[i].B;
    pixels[i].R = grayscaleValue;
    pixels[i].G = grayscaleValue;
    pixels[i].B = grayscaleValue;
  }
}

import java.awt.image.BufferedImage;
import java.io.File;
import java.io.IOException;
import javax.imageio.ImageIO;

public class GrayscaleConversion {
  public static void main(String[] args) throws IOException {
    // Load the RGB image
    BufferedImage img = ImageIO.read(new File('image.jpg'));

    // Convert the image to grayscale
    for (int x = 0; x < img.getWidth(); x++) {
      for (int y = 0; y < img.getHeight(); y++) {
        int rgb = img.getRGB(x, y);
        int R = (rgb >> 16) & 0xFF;
        int G = (rgb >> 8) & 0xFF;
        int B = rgb & 0xFF;
        int grayscaleValue = (int) (0.299 * R + 0.587 * G + 0.114 * B);
        img.setRGB(x, y, (grayscaleValue << 16) | (grayscaleValue << 8) | grayscaleValue);
      }
    }

    // Save the grayscale image
    ImageIO.write(img, 'jpg', new File('grayscale_image.jpg'));
  }
}
